#include <bits/stdc++.h>
using namespace std;
const int maxn=1e7+5;
int k,l,r,L,R,a[40],b[maxn],ll,t;
void jj(int x) {
	for(int i=1; i<x; i++) {
		for(int j=0; j<x; j++) {
			if(i!=j) {
				ll=0;
				t=0;
				while(t<r) {
					ll++;
					if(ll%2==0) {
						a[ll]=i;
					} else {
						a[ll]=j;
					}
					t=t*x+a[ll];
					if(t>r) {
						break;
					}
					b[t]++;
				}
			}
		}
	}
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>L>>R>>l>>r>>k;
	for(int i=L; i<=R; i++) {
		jj(i);
	}
	for(int i=l; i<=r; i++) {
		if(b[i]==k) {
			cout<<i<<"\n";
		}
	}
	return 0;
}
